import socket
import json
import time
import hashlib
import secrets
from collections import defaultdict
from dataclasses import dataclass
from typing import Dict, Set
import threading

@dataclass
class RateLimitEntry:
    request_count: int
    first_request_time: float
    challenge_issued: bool
    challenge_token: str = ""
    challenge_time: float = 0

class SecureGameServer:
    def __init__(self, host='0.0.0.0', port=27015):
        self.host = host
        self.port = port
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        
        self.rate_limit_window = 10
        self.max_requests_per_window = 5
        self.rate_limit_data: Dict[str, RateLimitEntry] = {}
        self.cleanup_interval = 60
        
        self.challenge_timeout = 30
        self.max_response_size = 512
        
        self.players = [
            {"name": "Player1", "score": 100, "ping": 25},
            {"name": "Player2", "score": 85, "ping": 30},
            {"name": "Player3", "score": 120, "ping": 45},
        ]
        
        self.game_state = {
            "server_name": "Secure Game Server",
            "map": "de_dust2",
            "game_mode": "competitive",
            "max_players": 16,
            "current_players": len(self.players),
            "version": "1.0.0"
        }
        
        self.running = False
        self.cleanup_thread = None

    def generate_challenge(self) -> str:
        return secrets.token_hex(16)

    def verify_challenge(self, client_addr: str, challenge_response: str) -> bool:
        if client_addr not in self.rate_limit_data:
            return False
        
        entry = self.rate_limit_data[client_addr]
        
        if not entry.challenge_issued:
            return False
        
        if time.time() - entry.challenge_time > self.challenge_timeout:
            return False
        
        expected_response = hashlib.sha256(entry.challenge_token.encode()).hexdigest()
        
        return challenge_response == expected_response

    def check_rate_limit(self, client_addr: str) -> tuple[bool, bool]:
        current_time = time.time()
        
        if client_addr not in self.rate_limit_data:
            self.rate_limit_data[client_addr] = RateLimitEntry(
                request_count=1,
                first_request_time=current_time,
                challenge_issued=False
            )
            return True, False
        
        entry = self.rate_limit_data[client_addr]
        
        if current_time - entry.first_request_time > self.rate_limit_window:
            entry.request_count = 1
            entry.first_request_time = current_time
            entry.challenge_issued = False
            return True, False
        
        entry.request_count += 1
        
        if entry.request_count > self.max_requests_per_window:
            if not entry.challenge_issued:
                return False, True
            return False, False
        
        return True, False

    def create_chunked_response(self, data: dict, chunk_id: int, total_chunks: int) -> bytes:
        chunk_data = {
            "chunk_id": chunk_id,
            "total_chunks": total_chunks,
            "data": data
        }
        return json.dumps(chunk_data).encode('utf-8')

    def create_summary_response(self) -> bytes:
        summary = {
            "type": "summary",
            "server_name": self.game_state["server_name"],
            "map": self.game_state["map"],
            "players": f"{self.game_state['current_players']}/{self.game_state['max_players']}",
            "info": "Send 'details:<challenge_response>' for full info"
        }
        return json.dumps(summary).encode('utf-8')

    def create_full_response(self) -> bytes:
        full_data = {
            "type": "full_status",
            "game_state": self.game_state,
            "players": self.players,
            "timestamp": time.time()
        }
        return json.dumps(full_data).encode('utf-8')

    def handle_request(self, data: bytes, addr: tuple):
        client_addr = addr[0]
        
        try:
            message = data.decode('utf-8').strip()
        except:
            return
        
        allowed, need_challenge = self.check_rate_limit(client_addr)
        
        if need_challenge:
            challenge = self.generate_challenge()
            entry = self.rate_limit_data[client_addr]
            entry.challenge_issued = True
            entry.challenge_token = challenge
            entry.challenge_time = time.time()
            
            response = json.dumps({
                "type": "challenge",
                "challenge": challenge,
                "message": "Rate limit exceeded. Solve challenge: SHA256(challenge)"
            }).encode('utf-8')
            
            self.sock.sendto(response[:self.max_response_size], addr)
            return
        
        if not allowed:
            response = json.dumps({
                "type": "error",
                "message": "Rate limit exceeded"
            }).encode('utf-8')
            self.sock.sendto(response[:self.max_response_size], addr)
            return
        
        if message.startswith("details:"):
            challenge_response = message.split(":", 1)[1]
            
            if self.verify_challenge(client_addr, challenge_response):
                entry = self.rate_limit_data[client_addr]
                entry.challenge_issued = False
                entry.request_count = 0
                entry.first_request_time = time.time()
                
                full_response = self.create_full_response()
                
                if len(full_response) > self.max_response_size:
                    response = json.dumps({
                        "type": "error",
                        "message": "Response too large. Use summary endpoint."
                    }).encode('utf-8')
                    self.sock.sendto(response[:self.max_response_size], addr)
                else:
                    self.sock.sendto(full_response, addr)
            else:
                response = json.dumps({
                    "type": "error",
                    "message": "Invalid or expired challenge response"
                }).encode('utf-8')
                self.sock.sendto(response[:self.max_response_size], addr)
            return
        
        if message == "status" or message == "info":
            summary_response = self.create_summary_response()
            self.sock.sendto(summary_response[:self.max_response_size], addr)
            return
        
        response = json.dumps({
            "type": "error",
            "message": "Unknown command. Use 'status' for server info."
        }).encode('utf-8')
        self.sock.sendto(response[:self.max_response_size], addr)

    def cleanup_old_entries(self):
        while self.running:
            time.sleep(self.cleanup_interval)
            current_time = time.time()
            
            to_remove = []
            for addr, entry in self.rate_limit_data.items():
                if current_time - entry.first_request_time > self.rate_limit_window * 2:
                    to_remove.append(addr)
            
            for addr in to_remove:
                del self.rate_limit_data[addr]

    def start(self):
        self.running = True
        self.cleanup_thread = threading.Thread(target=self.cleanup_old_entries, daemon=True)
        self.cleanup_thread.start()
        
        print(f"Secure game server listening on {self.host}:{self.port}")
        print(f"Rate limit: {self.max_requests_per_window} requests per {self.rate_limit_window} seconds")
        print(f"Max response size: {self.max_response_size} bytes")
        
        while self.running:
            try:
                data, addr = self.sock.recvfrom(1024)
                threading.Thread(target=self.handle_request, args=(data, addr), daemon=True).start()
            except KeyboardInterrupt:
                break
            except Exception as e:
                print(f"Error: {e}")
        
        self.stop()

    def stop(self):
        self.running = False
        self.sock.close()
        print("Server stopped")

if __name__ == "__main__":
    server = SecureGameServer(port=27015)
